<?php
require_once __DIR__ . '/teklif-db.php';
require_login();

$offerId = (int)($_GET['id'] ?? 0);
$offer = teklif_load($offerId);
if (!$offer) {
    flash('error', 'PDF alınacak teklif bulunamadı.');
    redirect('teklif-ver.php');
}

$title = $offer['document_title'] ?: 'SİPARİŞ FİŞİ';
$offerNo = $offer['offer_no'] ?: '';
$offerDate = $offer['offer_date'] ?: date('Y-m-d');
$customer = $offer['customer_name'] ?: '';
$city = $offer['customer_city'] ?: '';
$customerAddress = trim((string)($offer['customer_address'] ?? ''));
$customerTaxOffice = trim((string)($offer['customer_tax_office'] ?? ''));
$customerTaxNo = trim((string)($offer['customer_tax_no'] ?? ''));
$customerPhone = trim((string)($offer['customer_phone'] ?? ''));
$currency = $offer['currency'] ?: 'TL';
$quantityLabel = $offer['quantity_label'] ?: 'DZ';
$note = $offer['note'] ?: '';
$footerText = $offer['footer_text'] ?: 'MALIMIZDAN HAYIR GÖRÜN.';
$termText = $offer['term_text'] ?: '';
$subtotal = (float)($offer['subtotal'] ?? 0);
$discountEnabled = (int)($offer['discount_enabled'] ?? 0) === 1;
$discountRate = (float)($offer['discount_rate'] ?? 0);
$discountAmount = (float)($offer['discount_amount'] ?? 0);
$vatEnabled = (int)($offer['vat_enabled'] ?? 0) === 1;
$vatRate = (float)($offer['vat_rate'] ?? 10);
$vatAmount = (float)($offer['vat_amount'] ?? 0);
$grandTotal = (float)($offer['grand_total'] ?? ($subtotal - $discountAmount + $vatAmount));
$rows = $offer['items'] ?? [];
$hasProductType = false;
foreach ($rows as $r) {
    if (trim((string)($r['product_type'] ?? '')) !== '') {
        $hasProductType = true;
        break;
    }
}
while (count($rows) < 13) {
    $rows[] = ['product_barcode'=>'', 'product_name'=>'', 'product_type'=>'', 'quantity'=>0, 'unit_price'=>0, 'line_total'=>0];
}
$totalBlankColspan = $hasProductType ? 4 : 3;
$docTypeLabel = (mb_stripos($title, 'SİPARİŞ') !== false || mb_stripos($title, 'SIPARIS') !== false) ? 'SİPARİŞ' : 'TEKLİF';
$logoSrc = 'assets/dumanlar-logo-arkaplansiz.png?v=20';
$hasCustomerInfo = $customerAddress !== '' || $customerTaxOffice !== '' || $customerTaxNo !== '' || $customerPhone !== '';
?>
